(function (global) {
  const OP_SET_TEXT = 1;
  const OP_SET_ATTR = 2;
  const OP_ADD_LISTENER = 3;
  const OP_REMOVE_LISTENER = 4;
  const OP_SET_CLASS = 5;
  const OP_INSERT_NODE = 6;
  const OP_REMOVE_NODE = 7;
  const OP_REPLACE_INNER = 8;
  const OP_ATTACH = 9;

  const EVENT_CLICK = 1;
  const EVENT_INPUT = 2;
  const EVENT_CHANGE = 3;
  const EVENT_SUBMIT = 4;

  const decoder = new TextDecoder();
  const encoder = new TextEncoder();

  function readString(memory, offset, length) {
    const view = new Uint8Array(memory.buffer, offset, length);
    return decoder.decode(view);
  }

  function readEventName(kind) {
    switch (kind) {
      case EVENT_CLICK:
        return "click";
      case EVENT_INPUT:
        return "input";
      case EVENT_CHANGE:
        return "change";
      case EVENT_SUBMIT:
        return "submit";
      default:
        return "unknown";
    }
  }

  function createRuntime(memory, exports) {
    const listeners = new Map();
    const events = [];

    function applyPendingCommands() {
      if (
        !exports ||
        typeof exports.__forge_pull_commands_ptr !== "function" ||
        typeof exports.__forge_pull_commands_len !== "function"
      ) {
        return;
      }
      const ptr = exports.__forge_pull_commands_ptr();
      const len = exports.__forge_pull_commands_len();
      if (!ptr || !len) {
        return 0;
      }
      return applyCommands(new Int32Array(memory.buffer, ptr, len));
    }

    function applyCommands(buf) {
      let touched = 0;
      for (let i = 0; i < buf.length; ) {
        const opcode = buf[i++];
        if (opcode === OP_SET_TEXT) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const valueOffset = buf[i++];
          const valueLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const value = readString(memory, valueOffset, valueLength);
          const element = document.getElementById(id);
          if (element) {
            element.textContent = value;
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_SET_ATTR) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const nameOffset = buf[i++];
          const nameLength = buf[i++];
          const valueOffset = buf[i++];
          const valueLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const name = readString(memory, nameOffset, nameLength);
          const value = readString(memory, valueOffset, valueLength);
          const element = document.getElementById(id);
          if (element) {
            element.setAttribute(name, value);
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_SET_CLASS) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const valueOffset = buf[i++];
          const valueLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const value = readString(memory, valueOffset, valueLength);
          const element = document.getElementById(id);
          if (element) {
            element.className = value;
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_INSERT_NODE) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const htmlOffset = buf[i++];
          const htmlLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const html = readString(memory, htmlOffset, htmlLength);
          const element = document.getElementById(id);
          if (element) {
            element.innerHTML = html;
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_REMOVE_NODE) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const element = document.getElementById(id);
          if (element) {
            element.innerHTML = "";
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_REPLACE_INNER) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const htmlOffset = buf[i++];
          const htmlLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const html = readString(memory, htmlOffset, htmlLength);
          const element = document.getElementById(id);
          if (element) {
            element.innerHTML = html;
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_ATTACH) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const element = document.getElementById(id);
          if (element && typeof element.setAttribute === "function") {
            element.setAttribute("data-bloom-attached", "true");
            touched += 1;
          }
          continue;
        }

        if (opcode === OP_ADD_LISTENER || opcode === OP_REMOVE_LISTENER) {
          const targetOffset = buf[i++];
          const targetLength = buf[i++];
          const eventOffset = buf[i++];
          const eventLength = buf[i++];
          const handlerId = buf[i++];
          const id = readString(memory, targetOffset, targetLength);
          const eventName = readString(memory, eventOffset, eventLength);
          const key = id + ":" + eventName + ":" + handlerId;
          const element = document.getElementById(id);
          if (!element) {
            continue;
          }

          if (opcode === OP_ADD_LISTENER) {
            if (listeners.has(key)) {
              continue;
            }
            const listener = function () {
              events.push({ kind: eventName, targetId: id });
              flushEvents();
            };
            listeners.set(key, listener);
            element.addEventListener(eventName, listener);
            touched += 1;
          } else {
            const listener = listeners.get(key);
            if (listener) {
              element.removeEventListener(eventName, listener);
              listeners.delete(key);
              touched += 1;
            }
          }
          continue;
        }

        throw new Error("Unknown Bloom DOM opcode: " + opcode);
      }
      return touched;
    }

    function flushEvents() {
      if (!exports || typeof exports.__forge_receive_events !== "function") {
        return;
      }
      while (events.length > 0) {
        const event = events.shift();
        let kind = EVENT_CLICK;
        if (event.kind === "input") kind = EVENT_INPUT;
        if (event.kind === "change") kind = EVENT_CHANGE;
        if (event.kind === "submit") kind = EVENT_SUBMIT;
        if (typeof exports.alloc === "function") {
          const bytes = encoder.encode(event.targetId);
          const ptr = exports.alloc(bytes.length);
          new Uint8Array(memory.buffer, ptr, bytes.length).set(bytes);
          exports.__forge_receive_events(kind, ptr, bytes.length);
          applyPendingCommands();
        } else {
          exports.__forge_receive_events(kind, event.targetId);
        }
      }
    }

    return {
      applyCommands,
      flushEvents,
      applyPendingCommands,
      readEventName,
    };
  }

  async function load(url) {
    const response = await fetch(url);
    const bytes = await response.arrayBuffer();
    const result = await WebAssembly.instantiate(bytes, {});
    const memory = result.instance.exports.memory;
    const runtime = createRuntime(memory, result.instance.exports);
    let attached = 0;
    if (typeof result.instance.exports.__forge_attach === "function") {
      result.instance.exports.__forge_attach();
      attached = runtime.applyPendingCommands();
    }
    if (!attached && typeof result.instance.exports.__forge_init === "function") {
      result.instance.exports.__forge_init();
      runtime.applyPendingCommands();
    }
    return {
      instance: result.instance,
      memory,
      runtime,
    };
  }

  global.ForgeBloom = {
    load,
    createRuntime,
    constants: {
      OP_SET_TEXT,
      OP_SET_ATTR,
      OP_ADD_LISTENER,
      OP_REMOVE_LISTENER,
      OP_SET_CLASS,
      OP_INSERT_NODE,
      OP_REMOVE_NODE,
      OP_REPLACE_INNER,
      OP_ATTACH,
      EVENT_CLICK,
      EVENT_INPUT,
      EVENT_CHANGE,
      EVENT_SUBMIT,
    },
  };
})(globalThis);
